code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100vh;
  background: #4c5425;
}

.container {
  position: relative;
  width: 100%;
  height: 100vh;
  overflow: hidden;
}

.header {
  position: relative;
  width: 100%;
  height: 100vh;
  top: -4rem;
  left: 2rem;
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 80px;
  font-family: "Pistilli";
  color: #aac728;
}

.letter-wrap {
  position: relative;
}

.letter {
  position: relative;
  top: 0;
}

.letter-reveal:before {
  content: "";
  position: absolute;
  top: 100px;
  left: -40px;
  width: 150px;
  height: 100px;
  background: #4c5425;
  animation: fadeOutPls 3s ease-in-out forwards;
  animation-delay: 2s;
}

@keyframes fadeOutPls {
  0% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}

.circle {
  opacity: 0;
  animation: circleScale 3s ease-in-out infinite;
  animation-delay: 10s;
}

.a .circle {
  position: absolute;
  top: 28px;
  left: 6px;
  width: 16px;
  height: 16px;
  border-radius: 100%;
  background: #aac728;
  animation-delay: 9s;
}

.a2 .circle {
  position: absolute;
  top: 28px;
  left: 6px;
  width: 16px;
  height: 16px;
  border-radius: 100%;
  background: #aac728;
  animation-delay: 9.75s;
}

.y .circle {
  position: absolute;
  top: 66px;
  left: 7px;
  width: 16px;
  height: 16px;
  border-radius: 100%;
  background: #aac728;
  animation-delay: 10.5s;
}

@keyframes circleScale {
  0% {
    transform: scale(10);
  }
  50% {
    transform: scale(7);
  }
  100% {
    transform: scale(10);
  }
}

/* extra stuff */

nav {
  position: fixed;
  width: 100%;
  z-index: 2;
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 2em 4em;
  font-family: "Neue Montreal";
  color: #aac728;
}

.nav-items {
  display: flex;
}

nav a,
.menu-toggle {
  position: relative;
  top: 0;
  padding: 0 4em;
  text-decoration: none;
  text-transform: uppercase;
  font-size: 14px;
  color: #aac728;
}

#logo a {
  margin-right: 8em;
}

section.bottom-nav {
  position: absolute;
  bottom: 1em;
  width: 100%;
  display: flex;
  justify-content: space-between;
  padding: 3em 8em;
  font-family: "Neue Montreal";
  color: #aac728;
  text-transform: uppercase;
  font-size: 14px;
}

.about a {
  text-decoration: none;
  text-transform: uppercase;
  font-size: 14px;
  line-height: 100%;
}

p#about {
  width: 50%;
  font-family: "Neue Montreal";
  font-size: 14px;
  line-height: 100%;
  text-transform: uppercase;
}

.location {
  position: relative;
  width: 30%;
  height: 60px;
  font-size: 14px;
  display: flex;
  text-transform: uppercase;
  justify-content: space-between;
}

.country {
  padding: 0.4em;
  width: 100%;
  display: flex;
  justify-content: flex-end;
  align-items: flex-start;
  text-align: right;
}

.country div {
  padding-left: 2em;
}
